import { BrowserRouter as Router, Route, Routes, Navigate } from 'react-router-dom';


import Home from './components/frontend/Home';
import Login from './layouts/frontend/auth/login';
import Register from './layouts/frontend/auth/register';
import AdminPrivateRoute from './routes/AdminPrivateRoute';
import adminRoutes from './routes/routes';
import PublicRoute from './routes/PublicRoute';
import Page403 from './components/errors/Page403';
import Page404 from './components/errors/Page404';
import Swal from 'sweetalert2';
import axios from 'axios';
import 'bootstrap/dist/css/bootstrap.min.css';
import '@fortawesome/fontawesome-free/css/all.min.css';

// Axios configuration
axios.defaults.baseURL = 'http://127.0.0.1:8000';
axios.defaults.headers.post['Content-Type'] = 'application/json';
axios.defaults.headers.post['Accept'] = 'application/json';
axios.defaults.withCredentials = true;

// Add request interceptor to include auth token
axios.interceptors.request.use(
  (config) =>
  {
    const token = localStorage.getItem('auth_token');
    if (token)
    {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) =>
  {
    return Promise.reject(error);
  }
);

// Add a response interceptor to handle 401 and 403 errors globally
axios.interceptors.response.use(
  (response) => response, // Pass through successful responses
  (error) => {
    const { status, data, config } = error.response || {};

    if (status === 401) {
      // Let AdminPrivateRoute handle its own 401 for the initial user check.
      // This prevents the global handler from redirecting before the private route can.
      if (config && config.url.endsWith('/api/user')) {
        return Promise.reject(error); // Pass it on to the component's .catch()
      }

      // For all other 401s, it means the token is invalid or expired.
      // Log the user out and redirect to login.
      localStorage.removeItem('auth_token');
      localStorage.removeItem('auth_user');
      Swal.fire({
        title: 'Unauthorized',
        text: data?.message || 'Your session has expired. Please log in again.',
        icon: 'warning',
        confirmButtonText: 'OK'
      }).then(() => {
        window.location.href = '/login';
      });
    }

    return Promise.reject(error);
  }
);

function App()
{
  return (
    <div className="App">
      <Router>
        <Routes>
          {/* The root path now defaults to the Home component, accessible to all. */}
          <Route path="/" element={<Home />} />
          {/* Public and Authentication Routes */}
          <Route path="/register" element={<PublicRoute><Register /></PublicRoute>} />
          <Route path="/login" element={<PublicRoute><Login /></PublicRoute>} />

          {/* Path to error page */}
          <Route path="/403" element={<Page403 />} />
          <Route path="/404" element={<Page404 />} />


          {/* Protected Admin Routes */}
          {/* The AdminPrivateRoute now acts as a layout wrapper for all nested admin routes.
              It will render MasterLayout, which in turn renders the <Outlet /> for its children. */}
          <Route path="/admin" element={<AdminPrivateRoute />}>
            {/* Map over your admin routes to create the nested <Route> elements */}
            {adminRoutes.map((route, idx) => (
              route.component && <Route key={idx} path={route.path} element={<route.component />} />
            ))}
            {/* This is the default page for "/admin". It redirects to the dashboard. */}
            <Route index element={<Navigate to="dashboard" replace />} />
          </Route>

        </Routes>
      </Router>
    </div>
  );
}

export default App;
